// Script: generar_35_editar_eliminar_antiparasitarios.js
// Que hace: replica a Antiparasitarios el mismo patron de editar/eliminar
// que ya armamos para Vacunas. Cada tarjeta de antiparasitario ahora
// tiene su boton de menu (\u22ee) con Editar y Eliminar.
//
// Como correrlo: node generar_35_editar_eliminar_antiparasitarios.js
// Confirma "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

const filePath = path.join('app', 'prevencion', 'page.tsx');
const b64 = "";
const content = Buffer.from(b64, 'base64').toString('utf8');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(filePath, content, 'utf8');
console.log('OK: ' + filePath);
